    def cancel_order(self, id: str, symbol: Str = None, params={}):
        """
        cancels an open order

        https://github.com/zebpay/zebpay-api-references/blob/main/spot/api-reference/private-endpoints.md#cancel-order
        https://github.com/zebpay/zebpay-api-references/blob/main/spot/api-reference/private-endpoints.md#cancel-all-orders-for-a-symbol

        :param str id: order id
        :param str symbol: unified symbol of the market the order was made in
        :param dict [params]: extra parameters specific to the exchange API endpoint
        :param dict [params.timestamp]: Timestamp
        :returns dict: An `order structure <https://docs.ccxt.com/#/?id=order-structure>`
        """
        self.load_markets()
        timestamp = self.safe_integer(params, 'timestamp')
        params = self.omit(params, ['timestamp'])
        request: dict = {
            'timestamp': timestamp,
        }
        response = None
        if id is None:
            request['symbol'] = symbol
            response = self.privateDeleteExOrders(self.extend(request, params))
        else:
            request['orderId'] = id
            response = self.privateDeleteExOrdersOrderId(self.extend(request, params))
        if response.data == None:
            raise ExchangeError(json.dumps(response))
        #
        #    {
        #        "data": {
        #            "orderId": "12345",
        #            "symbol": 'BTC-INR
        #        },
        #    }
        #
        return response

