    def fetch_ohlcv(self, symbol: str, timeframe='1m', since: Int = None, limit: Int = None, params={}) -> List[list]:
        """
        fetches historical candlestick data containing the open, high, low, and close price, and the volume of a market

        https://github.com/zebpay/zebpay-api-references/blob/main/spot/api-reference/public-endpoints.md#get-klinescandlesticks

        :param str symbol: unified symbol of the market to fetch OHLCV data for
        :param str timeframe: the length of time each candle represents
        :param int [since]: timestamp in ms of the earliest candle to fetch
        :param int [limit]: the maximum amount of candles to fetch
        :param dict [params]: extra parameters specific to the exchange API endpoint
        :param int [params.endtime]: the latest time in ms to fetch orders for
        :returns int[][]: A list of candles ordered, open, high, low, close, volume
        """
        if symbol is None:
            raise ArgumentsRequired(self.id + ' fetchOHLCV() requires a symbol argument')
        endtime = self.safe_string(params, 'endTime')
        starttime = self.safe_string(params, 'startTime')
        params = self.omit(params, ['endtime'])
        self.load_markets()
        market = self.market(symbol)
        request: dict = {
            'symbol': market['id'],
        }
        if limit is None:
            limit = 200  # default is 200
        request['startTime'] = starttime
        request['limit'] = limit  # max 200, default 200
        request['endTime'] = endtime
        request['interval'] = timeframe
        response = None
        if market['spot']:
            request['category'] = 'spot'
            response = self.publicGetMarketKlines(self.extend(request, params))
        #
        #             [
        #                 [
        #                     "1670608800000",
