    def fetch_order(self, id: Str, symbol: Str = None, params={}):
        """
        fetches information on an order made by the user

        https://github.com/zebpay/zebpay-api-references/blob/main/spot/api-reference/private-endpoints.md#get-order-details

        :param str id: order id
        :param str symbol: unified symbol of the market the order was made in
        :param dict [params]: extra parameters specific to the exchange API endpoint
        :param str [params.timestamp]: cancel order by client order id
        :returns dict: An `order structure <https://docs.ccxt.com/#/?id=order-structure>`
        """
        self.load_markets()
        request: dict = {}
        timestamp = self.safe_integer(params, 'timestamp')
        if id is None:
            raise InvalidOrder(self.id + ' fetchOrder() requires parameter orderId in params')
        params = self.omit(params, ['timestamp'])
        request['orderId'] = id
        request['timestamp'] = timestamp
        response = self.privateGetExOrdersOrderId(self.extend(request, params))
        if response.data == None:
            raise ExchangeError(json.dumps(response))
        #
        #     {
        #         "data": {
        #                     "orderId": "64507d02921f1c0001ff6892-123-zeb",
        #                     "datetime": "2025-03-14T14:34:34.4567",
        #                     "timestamp": 1741962557553,
        #                     "status": "open",
        #                     "origQty": "12",
        #                     "symbol": "BTCINR",
        #                     "type": "market",
        #                     "side": "buy",
        #                     "price": 700000,
        #                     "avgExecutedPrice": 0,
        #                     "filledQty": "0",
        #                     "openQty": 0.002,
        #                     "feeCurrency": "INR",
        #                     "fees": "0",
        #                     "tds": "0",
        #                     "tax": "0"
        #                 }
        #     }
        #
        market = self.market(symbol) if (symbol is not None) else None
        responseData = self.safe_dict(response, 'data')
        return self.parse_order(responseData, market)

    def fetch_open_orders(self, symbol: Str = None, since: Int = None, limit: Int = None, params={}) -> List[Order]:
        """
        fetch all unfilled currently open orders

        https://github.com/zebpay/zebpay-api-references/blob/main/spot/api-reference/private-endpoints.md#get-orders

        :param str [symbol]: unified market symbol
        :param int [since]: the earliest time in ms to fetch open orders for
        :param int [limit]: the maximum number of  open orders structures to retrieve
        :param dict [params]: extra parameters specific to the exchange API endpoint
        :param str [params.timestamp]: the orders client order id
        :returns Order[]: a list of `order structures <https://docs.ccxt.com/#/?id=order-structure>`
        """
        self.load_markets()
        status = self.safe_string(params, 'status')
        timestamp = self.safe_integer(params, 'timestamp')
        request: dict = {
            'currentPage': 1,
            'pageSize': limit or 100,
            'symbol': symbol,
            'status': status,
            'timestamp': timestamp,
        }
        params = self.omit(params, ['status', 'timestamp'])
        response = self.privateGetExOrders(self.extend(request, params))
        if response.data == None:
            raise ExchangeError(json.dumps(response))
        #
        #     {
        #         "data": {
        #             "items": [
        #                   {
        #                      "orderId": "64507d02921f1c0001ff6892-123-zeb",
        #                      "datetime": "2025-03-14T14:34:34.4567",
        #                      "timestamp": 1741962557553,
        #                      "status": "open",
        #                      "symbol": "BTCINR",
        #                      "type": "market",
        #                      "side": "buy",
        #                      "price": "700000",
        #                      "avgExecutedPrice": "0",
        #                      "filled": null,
        #                      "remaining": 0.002,
        #                      "filledQty": "0",
        #                      "openQty": 0.002,
        #                      "feeCurrency": "INR",
        #                      "fees": "0",
        #                      "tds": "0",
        #                      "tax": "0"
        #                  }
        #              ]
        #           }
        #     }
        #
        market = None
        if symbol is not None:
            market = self.market(symbol)
        result = self.safe_dict(response, 'data', {})
        items = self.safe_list(result, 'items', [])
        return self.parse_orders(items, market, None, limit)

    def fetch_order_trades(self, id: str, symbol: Str = None, since: Int = None, limit: Int = None, params={}):
        """
        fetch all the trades made from a single order

        https://github.com/zebpay/zebpay-api-references/blob/main/spot/api-reference/private-endpoints.md#get-order-fills

        :param str id: order id
        :param str symbol: unified market symbol
        :param int [since]: the earliest time in ms to fetch trades for
        :param int [limit]: the maximum number of trades to retrieve
        :param dict [params]: extra parameters specific to the exchange API endpoint
        :returns dict[]: a list of `trade structures <https://docs.ccxt.com/#/?id=trade-structure>`
        """
        self.load_markets()
        timestamp = self.safe_integer(params, 'timestamp')
        request: dict = {
            'orderId': id,
            'timestamp': timestamp,
        }
        params = self.omit(params, ['timestamp'])
        response = self.privateGetExOrdersFillsOrderId(self.extend(request, params))
        if response.data == None:
            raise ExchangeError(json.dumps(response))
        #
        #         {
        #             "orderId": "456789",
        #             "symbol": "LINK_USDT",
        #             "origQty": "1.5",
        #             "orderId": "30249408733945856",
        #             "side": "BUY",
        #             "type": "LIMIT",
        #             "matchRole": "MAKER",
        #             "createTime": 1648200366864,
        #             "price": "3.1",
        #             "avgExecutedPrice": "2.3456"
        #             "openQty": "1",
        #             "filledQty": "0",
        #             "fees": "0.00145",
        #         }
        #
        data = self.safe_dict(response, 'data', {})
        trades = [data]
        return self.parse_trades(trades)

    def parse_trades(self, trades: List[Any], market: Market = None, since: Int = None, limit: Int = None, params={}) -> List[Trade]:
        trades = self.to_array(trades)
        result = []
        for i in range(0, len(trades)):
            trade = self.extend(self.parse_trade(trades[i], market), params)
            result.append(trade)
        result = self.sort_by_2(result, 'timestamp', 'id')
        symbol = market['symbol'] if (market is not None) else None
        return self.filter_by_symbol_since_limit(result, symbol, since, limit)

    def parse_trade(self, trade: dict, market: Market = None) -> Trade:
        #
        # fetchMyTrades
        #
        #     {
        #         "id": "32164924331503616",
        #         "symbol": "LINK_USDT",
        #         "accountType": "SPOT",
        #         "orderId": "32164923987566592",
        #         "side": "SELL",
        #         "type": "MARKET",
        #         "matchRole": "TAKER",
        #         "createTime": 1648635115525,
        #         "price": "11",
        #         "quantity": "0.5",
        #         "amount": "5.5",
        #         "feeCurrency": "USDT",
        #         "feeAmount": "0.007975",
        #         "pageId": "32164924331503616",
        #         "clientOrderId": "myOwnId-321"
        #     }
        #
        #
        id = None
        orderId = self.safe_integer(trade, 'orderId')
        timestamp = self.safe_integer(trade, 'createdAt')
        marketId = self.safe_string(trade, 'symbol')
        market = self.safe_market(marketId, market, '_')
        symbol = market['symbol']
        side = self.safe_string_lower(trade, 'side')
        priceString = self.safe_string(trade, 'price')
        amountString = self.safe_string(trade, 'openQty')
        fees = self.safe_string(trade, 'fees')
        return self.safe_trade({
            'id': id,
            'info': trade,
            'timestamp': timestamp,
            'datetime': self.iso8601(timestamp),
            'symbol': symbol,
            'order': orderId,
            'type': self.safe_string_lower(trade, 'type'),
            'side': side,
            'takerOrMaker': None,
            'price': priceString,
            'amount': amountString,
            'cost': None,
            'fee': fees,
        }, market)

