    def parse_order(self, order: dict, market: Market = None) -> Order:
        #
        #      {
        #          "orderId": "64507d02921f1c0001ff6892-123-zeb",
        #          "datetime": "2025-03-14T14:34:34.4567",
        #          "timestamp": 1741962557553,
        #          "status": "open",
        #          "symbol": "BTCINR",
        #          "type": "market",
        #          "side": "buy",
        #          "price": "700000",
        #          "avgExecutedPrice": "0",
        #          "filled": null,
        #          "remaining": 0.002,
        #          "filledQty": "0",
        #          "openQty": 0.002,
        #          "feeCurrency": "INR",
        #          "fees": "0",
        #          "tds": "0",
        #          "tax": "0"
        #      }
        #
        marketId = self.safe_string(order, 'symbol')
        market = self.safe_market(marketId, market)
        symbol = market['symbol']
        type = self.safe_string(order, 'type')
        timestamp = self.safe_integer(order, 'createdAt')
        datetime = self.iso8601(timestamp)
        price = self.safe_string(order, 'price')
        side = self.safe_string(order, 'side')
        amount = self.safe_string(order, 'origQty')
        filled = self.safe_string(order, 'filledQty')
        remaining = self.safe_string(order, 'openQty')
        orderId = self.safe_string(order, 'orderId')
        timeInForce = None
        status = self.safe_string(order, 'status')
        return self.safe_order({
            'id': orderId,
            'symbol': symbol,
            'type': type,
            'timeInForce': timeInForce,
            'postOnly': None,
            'reduceOnly': None,
            'side': side,
            'amount': amount,
            'price': price,
            'triggerPrice': None,
            'cost': None,
            'filled': filled,
            'remaining': remaining,
            'timestamp': timestamp,
            'datetime': datetime,
            'fee': None,
            'status': status,
            'info': order,
            'lastTradeTimestamp': None,
            'lastUpdateTimestamp': None,
            'average': None,
            'trades': None,
        }, market)

    def order_request(self, symbol, type, amount, request, price=None, params={}):
        upperCaseType = type.upper()
        triggerPrice = self.safe_string(params, 'stopPrice')
        timestamp = self.safe_integer(params, 'timestamp')
        quoteOrderQty = self.safe_string(params, 'quoteOrderQty')
        params = self.omit(params, ['stopPrice', 'timestamp', 'quoteOrderQty'])
        request['type'] = upperCaseType
        if upperCaseType == 'MARKET':
            if quoteOrderQty is None:
                raise ExchangeError(self.id + ' market createOrder() requires quoteOrderQty')
            request['quoteOrderQty'] = quoteOrderQty
        else:
            request['stopPrice'] = triggerPrice
            request['quantity'] = str(amount)
            request['price'] = str(price)
        request['timestamp'] = timestamp
        return [request, params]

    def parse_balance(self, response) -> Balances:
        result: dict = {
            'info': response,
            'timestamp': None,
            'datetime': None,
        }
        currencyList = self.safe_list(response, 'data')
        for i in range(0, len(currencyList)):
            entry = currencyList[i]
            account = self.account()
            account['total'] = self.safe_string(entry, 'balance')
            account['free'] = self.safe_string(entry, 'available')
            account['used'] = self.safe_string(entry, 'locked')
            currencyId = self.safe_string(entry, 'currency')
            code = self.safe_currency_code(currencyId)
            result[code] = account
        return self.safe_balance(result)

    def sign(self, path, api='public', method='GET', params={}, headers=None, body=None):
        url = self.urls['api'][api]
        versions = self.safe_value(self.options, 'versions', {})
        apiVersions = self.safe_value(versions, api, {})
        methodVersions = self.safe_value(apiVersions, method, {})
        defaultVersion = self.safe_string(methodVersions, path, self.version)
        version = self.safe_string(params, 'version', defaultVersion)
        tail = '/api/' + version + '/' + self.implode_params(path, params)
        url += tail
        # timestamp = str(self.milliseconds())
        signature = ''
        query = self.omit(params, self.extract_params(path))
        queryLength = query
        if api == 'public':
            if queryLength:
                url += '?' + self.urlencode(query)
        else:
            self.check_required_credentials()
            if method == 'GET' or method == 'DELETE':
                # For GET/DELETE: Append params to URL and sign the query string
                # params['timestamp'] = timestamp
                if method == 'DELETE' and path.includes('ex/orders'):
                    params = self.omit(params, 'orderId')
                if method == 'GET' and path.includes('ex/orders/'):
                    params = self.omit(params, 'orderId')
                queryString = self.urlencode(params)
                signature = self.hmac(queryString, self.secret, hashlib.sha256, 'hex')
                url += '?' + queryString
            else:
                # For POST/PUT: Convert body to JSON and sign the stringified payload
                # params['timestamp'] = timestamp
                body = json.dumps(params)
                signature = self.hmac(body, self.secret, hashlib.sha256, 'hex')
            headers = {
                'X-AUTH-APIKEY': self.apiKey,
                'X-AUTH-SIGNATURE': signature,
            }
            headers['Content-Type'] = 'application/json'
        return {'url': url, 'method': method, 'body': body, 'headers': headers}

    def handle_errors(self, code: int, reason: str, url: str, method: str, headers: dict, body: str, response, requestHeaders, requestBody):
        if not response:
            self.throw_broadly_matched_exception(self.exceptions['broad'], body, body)
            return None
        #
        # bad
        #     {"code": "400100", "msg": "validation.createOrder.clientOidIsRequired"}
        # good
        #     {code: "200000", data: {...}}
        #
        errorCode = self.safe_string(response, 'code')
        message = self.safe_string(response, 'msg', '')
        feedback = self.id + ' ' + message
        self.throw_exactly_matched_exception(self.exceptions['exact'], message, feedback)
        self.throw_exactly_matched_exception(self.exceptions['exact'], errorCode, feedback)
        self.throw_broadly_matched_exception(self.exceptions['broad'], body, feedback)
        return None
